use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use reqwest::Client;
use std::collections::HashSet;

const ALLOWED_DOMAINS: &[&str] = &["example.com", "api.example.com"];

fn is_allowed_domain(url: &str) -> bool {
    let allowed_domains: HashSet<&str> = ALLOWED_DOMAINS.iter().cloned().collect();
    if let Some(parsed_url) = url.parse::<url::Url>().ok() {
        allowed_domains.contains(&parsed_url.domain().unwrap_or(""))
    } else {
        false
    }
}

async fn forward_request(url: web::Query<String>) -> impl Responder {
    if !is_allowed_domain(&url.0) {
        return HttpResponse::Forbidden().body("Access denied");
    }

    let client = Client::new();
    match client.get(&url.0).send().await {
        Ok(response) => response.text().await.map_or_else(
            |err| HttpResponse::InternalServerError().body(err.to_string()),
            |text| HttpResponse::Ok().body(text),
        ),
        Err(err) => HttpResponse::InternalServerError().body(err.to_string()),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/forward", web::get().to(forward_request))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}